You are implementing Task 3 of the Digital Loyalty Card App.

**Context:** Turborepo monorepo at C:\Users\User\loyalty-app with pnpm workspaces. Expo mobile app already in apps/mobile. @loyalty/shared types in packages/shared. Node v20.20.0, pnpm 10.30.2.

**TASK: Next.js Merchant Dashboard Scaffold**

Execute IN ORDER. All paths relative to C:\Users\User\loyalty-app.

**Step 1: Create Next.js app**
```bash
cd /c/Users/User/loyalty-app/apps
npx create-next-app@latest dashboard --typescript --tailwind --eslint --app --src-dir --import-alias "@/*" --yes
```

**Step 2: Install Supabase SSR deps**
```bash
cd /c/Users/User/loyalty-app/apps/dashboard
pnpm add @supabase/supabase-js @supabase/ssr
```

**Step 3: Add shared workspace dep**
Add `"@loyalty/shared": "workspace:*"` to apps/dashboard/package.json dependencies.
```bash
cd /c/Users/User/loyalty-app && pnpm install
```

**Step 4: Install shadcn and components**
```bash
cd /c/Users/User/loyalty-app/apps/dashboard
npx shadcn@latest init -d
npx shadcn@latest add button card input label table dialog tabs badge select textarea toast
```
NOTE: If shadcn asks questions, accept ALL defaults.

**Step 5: Install lucide-react** (for icons)
```bash
cd /c/Users/User/loyalty-app/apps/dashboard
pnpm add lucide-react
```

**Step 6: Create Supabase server helper**
Create `apps/dashboard/src/lib/supabase/server.ts`:
```typescript
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';

export async function createClient() {
  const cookieStore = await cookies();
  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll(); },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) => cookieStore.set(name, value, options));
          } catch { /* Server Component read-only */ }
        },
      },
    }
  );
}
```

**Step 7: Create Supabase client helper**
Create `apps/dashboard/src/lib/supabase/client.ts`:
```typescript
import { createBrowserClient } from '@supabase/ssr';

export function createClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );
}
```

**Step 8: Create Supabase middleware helper**
Create `apps/dashboard/src/lib/supabase/middleware.ts`:
```typescript
import { createServerClient } from '@supabase/ssr';
import { NextResponse, type NextRequest } from 'next/server';

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({ request });
  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return request.cookies.getAll(); },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) => request.cookies.set(name, value));
          supabaseResponse = NextResponse.next({ request });
          cookiesToSet.forEach(({ name, value, options }) => supabaseResponse.cookies.set(name, value, options));
        },
      },
    }
  );
  const { data: { user } } = await supabase.auth.getUser();
  if (!user && !request.nextUrl.pathname.startsWith('/login') && !request.nextUrl.pathname.startsWith('/register')) {
    const url = request.nextUrl.clone();
    url.pathname = '/login';
    return NextResponse.redirect(url);
  }
  return supabaseResponse;
}
```

**Step 9: Create middleware.ts** at `apps/dashboard/middleware.ts` (NOT in src/):
Wait - actually Next.js with src dir wants middleware at root or src. Check if create-next-app put things in src/app or app/. The middleware should be at `apps/dashboard/src/middleware.ts` if using src dir:

```typescript
import { updateSession } from '@/lib/supabase/middleware';
import type { NextRequest } from 'next/server';

export async function middleware(request: NextRequest) {
  return await updateSession(request);
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico|login|register|api).*)'],
};
```

**Step 10: Create login page**
Create `apps/dashboard/src/app/login/page.tsx`:
```typescript
'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleLogin(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) { setError(error.message); setLoading(false); return; }
    router.push('/');
    router.refresh();
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50">
      <Card className="w-full max-w-md">
        <CardHeader><CardTitle>Merchant Login</CardTitle></CardHeader>
        <CardContent>
          <form onSubmit={handleLogin} className="space-y-4">
            <div><Label htmlFor="email">Email</Label><Input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} required /></div>
            <div><Label htmlFor="password">Password</Label><Input id="password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} required /></div>
            {error && <p className="text-sm text-red-500">{error}</p>}
            <Button type="submit" className="w-full" disabled={loading}>{loading ? 'Signing in...' : 'Sign In'}</Button>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}
```

**Step 11: Create dashboard sidebar component**
Create `apps/dashboard/src/components/dashboard-sidebar.tsx`:
```typescript
'use client';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { LayoutDashboard, CreditCard, Users, Megaphone, BarChart3, QrCode, Settings } from 'lucide-react';

const links = [
  { href: '/', label: 'Dashboard', icon: LayoutDashboard },
  { href: '/programs', label: 'Programs', icon: CreditCard },
