```

**Step 12: Create dashboard layout**
Create `apps/dashboard/src/app/(dashboard)/layout.tsx`:
```typescript
import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import { DashboardSidebar } from '@/components/dashboard-sidebar';

export default async function DashboardLayout({ children }: { children: React.ReactNode }) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  return (
    <div className="flex min-h-screen">
      <DashboardSidebar />
      <main className="flex-1 p-6 bg-gray-50">{children}</main>
    </div>
  );
}
```

**Step 13: Create dashboard home page**
Create `apps/dashboard/src/app/(dashboard)/page.tsx`:
```typescript
export default function DashboardPage() {
  return <div><h2 className="text-2xl font-bold">Dashboard</h2><p className="text-gray-500 mt-2">Welcome back. Your KPIs will appear here.</p></div>;
}
```

IMPORTANT: Remove/replace the default Next.js page.tsx that create-next-app generated at src/app/page.tsx. The (dashboard) route group's page.tsx should serve as the home page.

**Step 14: Create .env.example**
Create `apps/dashboard/.env.example`:
```
NEXT_PUBLIC_SUPABASE_URL=https://your-project.supabase.co
NEXT_PUBLIC_SUPABASE_ANON_KEY=your-anon-key
```

**Step 15: Commit**
```bash
cd /c/Users/User/loyalty-app && git add . && git commit -m "feat: scaffold Next.js merchant dashboard with auth and sidebar"
```

IMPORTANT: Create ALL files. If create-next-app generates a default page.tsx at src/app/page.tsx, remove it since (dashboard)/page.tsx will handle the root route.

